draw(Circle((-5,0),4));
draw((-10.5,0)--(10.5,0));
draw((0,-10.5)--(0,10.5));

label("$4$", (-3,0), N);
label("$4$", (-7,0), N);

dot("$-5$", (-5,0), S);
[/asy]

